// // This module compares four inputs A1, A2, A3, and B1 to produce an output Y.
// It outputs a logic LOW when all inputs are LOW (0000),
// a logic HIGH when all inputs are HIGH (1111),
// and outputs a logic LOW for any combination of inputs,
// while conversely outputting a logic HIGH for any combination that does not represent all HIGH.
module top_module(
    Y ,
    A1,
    A2,
    A3,
    B1
);output Y ;
    input  A1;
    input  A2;
    input  A3;
    input  B1;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    wire [3:0] input_signals;
    assign input_signals = {A1, A2, A3, B1};

    assign Y = (input_signals == 4'b0000) ? 1'b0 :
               (input_signals == 4'b1111) ? 1'b1 :
               (input_signals != 4'b0000) ? 1'b1 :
               (input_signals != 4'b1111) ? 1'b0 :
               1'bx;

endmodule

